import { WinstonModuleOptions } from 'nest-winston';
import * as winston from 'winston';

const { combine, timestamp, json, colorize, printf, errors } = winston.format;

const developmentFormat = combine(
  colorize({ all: true }),
  timestamp({ format: 'HH:mm:ss' }),
  errors({ stack: true }),
  printf(({ timestamp: ts, level, message, context, trace, ...meta }) => {
// eslint-disable-next-line @typescript-eslint/no-base-to-string, @typescript-eslint/restrict-template-expressions -- TODO(RC3): Address type safety
    const ctx = context ? `[${context}]` : '';
    const metaStr = Object.keys(meta).length ? ` ${JSON.stringify(meta)}` : '';
// eslint-disable-next-line @typescript-eslint/no-base-to-string, @typescript-eslint/restrict-template-expressions -- TODO(RC3): Address type safety
    const traceStr = trace ? `\n${trace}` : '';
// eslint-disable-next-line @typescript-eslint/restrict-template-expressions -- TODO(RC3): Address type safety
    return `${ts} ${level} ${ctx} ${message}${metaStr}${traceStr}`;
  }),
);

const productionFormat = combine(timestamp(), errors({ stack: true }), json());

export function createWinstonConfig(): WinstonModuleOptions {
  const isProduction = process.env.NODE_ENV === 'production';

  return {
    level: isProduction ? 'info' : 'debug',
    format: isProduction ? productionFormat : developmentFormat,
    defaultMeta: {
      service: 'shiftly-api',
      version: process.env.npm_package_version,
      environment: process.env.NODE_ENV,
    },
    transports: [
      new winston.transports.Console(),
      ...(isProduction
        ? [
            new winston.transports.File({
              filename: 'logs/error.log',
              level: 'error',
              maxsize: 10 * 1024 * 1024,
              maxFiles: 5,
            }),
            new winston.transports.File({
              filename: 'logs/combined.log',
              maxsize: 10 * 1024 * 1024,
              maxFiles: 10,
            }),
          ]
        : []),
    ],
    exceptionHandlers: [new winston.transports.Console()],
    rejectionHandlers: [new winston.transports.Console()],
  };
}

import { Test, TestingModule } from '@nestjs/testing';
import { PrismaService } from './prisma.service';
import { ConfigService } from '@nestjs/config';
import { Logger } from '@nestjs/common';

describe('PrismaService', () => {
  let service: PrismaService;
  let configService: ConfigService;

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [
        PrismaService,
        {
          provide: ConfigService,
          useValue: {
            get: jest.fn().mockReturnValue('development'),
          },
        },
      ],
    }).compile();

    service = module.get<PrismaService>(PrismaService);
    configService = module.get<ConfigService>(ConfigService);

    // Mock the connect/disconnect functions of PrismaClient
    service.$connect = jest.fn();
    service.$disconnect = jest.fn();
    service.$transaction = jest.fn();
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  it('should be defined', () => {
    expect(service).toBeDefined();
  });

  describe('Constructor (Logging)', () => {
    it('should log slow queries', () => {
      // We can manually call the event handler if we spy on it during a new instantiation
      // Or we can just spy on PrismaClient.prototype.$on before instantiation
      const onSpy = jest
// eslint-disable-next-line @typescript-eslint/no-require-imports, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
        .spyOn(require('@prisma/client').PrismaClient.prototype, '$on')
        .mockImplementation();

      const newService = new PrismaService(configService);
      expect(onSpy).toHaveBeenCalledWith('query', expect.any(Function));

// eslint-disable-next-line @typescript-eslint/no-unsafe-assignment -- TODO(RC3): Address type safety
      const callback = onSpy.mock.calls[0][1] as any;

      // Spy on logger
      const loggerSpy = jest
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
        .spyOn((newService as any).logger, 'warn')
        .mockImplementation();

      // Trigger with fast query
// eslint-disable-next-line @typescript-eslint/no-unsafe-call -- TODO(RC3): Address type safety
      callback({ query: 'SELECT 1', duration: 50 });
      expect(loggerSpy).not.toHaveBeenCalled();

      // Trigger with slow query
// eslint-disable-next-line @typescript-eslint/no-unsafe-call -- TODO(RC3): Address type safety
      callback({ query: 'SELECT 1', duration: 150 });
      expect(loggerSpy).toHaveBeenCalledWith('Slow query (150ms): SELECT 1');

      onSpy.mockRestore();
    });
  });

  describe('onModuleInit', () => {
    it('should connect to the database', async () => {
      await service.onModuleInit();
// eslint-disable-next-line @typescript-eslint/unbound-method -- TODO(RC3): Address type safety
      expect(service.$connect).toHaveBeenCalled();
    });

    it('should throw an error if connection fails', async () => {
      (service.$connect as jest.Mock).mockRejectedValueOnce(
        new Error('Connection failed'),
      );
      await expect(service.onModuleInit()).rejects.toThrow('Connection failed');
    });
  });

  describe('onModuleDestroy', () => {
    it('should disconnect from the database', async () => {
      await service.onModuleDestroy();
// eslint-disable-next-line @typescript-eslint/unbound-method -- TODO(RC3): Address type safety
      expect(service.$disconnect).toHaveBeenCalled();
    });
  });

  describe('softDelete', () => {
    it('should set deletedAt for a given model and id', async () => {
      const mockUpdate = jest.fn();
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      (service as any).user = { update: mockUpdate };

      await service.softDelete('user', '123');

      expect(mockUpdate).toHaveBeenCalledWith({
        where: { id: '123' },
// eslint-disable-next-line @typescript-eslint/no-unsafe-assignment -- TODO(RC3): Address type safety
        data: { deletedAt: expect.any(Date) },
      });
    });
  });

  describe('executeTransaction', () => {
    it('should execute a transaction', async () => {
      const mockTx = {};
      const mockFn = jest.fn().mockResolvedValue('result');
// eslint-disable-next-line @typescript-eslint/require-await -- TODO(RC3): Address type safety
      (service.$transaction as jest.Mock).mockImplementation(async (cb) => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-return, @typescript-eslint/no-unsafe-call -- TODO(RC3): Address type safety
        return cb(mockTx);
      });

      const result = await service.executeTransaction(mockFn);

      expect(mockFn).toHaveBeenCalledWith(mockTx);
      expect(result).toBe('result');
    });
  });
});

import {
  Injectable,
  OnModuleInit,
  OnModuleDestroy,
  Logger,
} from '@nestjs/common';
import { PrismaClient } from '@prisma/client';
import { ConfigService } from '@nestjs/config';

@Injectable()
export class PrismaService
  extends PrismaClient
  implements OnModuleInit, OnModuleDestroy
{
  private readonly logger = new Logger(PrismaService.name);

  constructor(private readonly configService: ConfigService) {
    super({
      log: [
        { emit: 'event', level: 'query' },
        { emit: 'event', level: 'error' },
        { emit: 'event', level: 'info' },
        { emit: 'event', level: 'warn' },
      ],
    });

    // Log slow queries in development
    if (configService.get<string>('app.nodeEnv') !== 'production') {
// eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      (this as any).$on(
        'query',
        (event: { query: string; duration: number }) => {
          if (event.duration > 100) {
            this.logger.warn(
              `Slow query (${event.duration}ms): ${event.query}`,
            );
          }
        },
      );
    }
  }

  async onModuleInit(): Promise<void> {
    try {
      await this.$connect();
      this.logger.log('Database connected');
    } catch (error) {
      this.logger.error('Failed to connect to database', error);
      throw error;
    }
  }

  async onModuleDestroy(): Promise<void> {
    await this.$disconnect();
    this.logger.log('Database disconnected');
  }

  /**
   * Soft-delete helper: sets deletedAt timestamp instead of physical deletion
   */
  async softDelete(model: string, id: string): Promise<void> {
// eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
    await (this as any)[model].update({
      where: { id },
      data: { deletedAt: new Date() },
    });
  }

  /**
   * Transaction wrapper with typed return
   */
  async executeTransaction<T>(
    fn: (
      tx: Omit<
        PrismaClient,
        | '$connect'
        | '$disconnect'
        | '$on'
        | '$transaction'
        | '$use'
        | '$extends'
      >,
    ) => Promise<T>,
  ): Promise<T> {
    return this.$transaction(fn);
  }
}

import { Test, TestingModule } from '@nestjs/testing';
import { RedisService } from './redis.service';
import { ConfigService } from '@nestjs/config';

jest.mock('ioredis', () => {
  const mRedis = jest.fn().mockImplementation(() => {
    return {
      on: jest.fn(),
      ping: jest.fn().mockResolvedValue('PONG'),
      quit: jest.fn().mockResolvedValue('OK'),
      get: jest.fn(),
      set: jest.fn(),
      del: jest.fn(),
      exists: jest.fn(),
      expire: jest.fn(),
      ttl: jest.fn(),
      incr: jest.fn(),
      incrby: jest.fn(),
      keys: jest.fn(),
      mget: jest.fn(),
      sadd: jest.fn(),
      srem: jest.fn(),
      sismember: jest.fn(),
      hset: jest.fn(),
      hget: jest.fn(),
      hdel: jest.fn(),
      hgetall: jest.fn(),
      publish: jest.fn(),
      pipeline: jest.fn(),
    };
  });
  return {
    __esModule: true,
    default: mRedis,
    Redis: mRedis,
  };
});

describe('RedisService', () => {
  let service: RedisService;
  let client: any;

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [
        RedisService,
        {
          provide: ConfigService,
          useValue: {
            get: jest.fn().mockReturnValue('localhost'),
          },
        },
      ],
    }).compile();

    service = module.get<RedisService>(RedisService);
// eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
    client = (service as any).client;
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('Events and Retry Strategy', () => {
    it('should attach error and reconnecting listeners', () => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      expect(client.on).toHaveBeenCalledWith('error', expect.any(Function));
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      expect(client.on).toHaveBeenCalledWith(
        'reconnecting',
        expect.any(Function),
      );
    });

    it('should trigger error listener', () => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      const errorFn = client.on.mock.calls.find(
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
        (call: any) => call[0] === 'error',
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      )[1];
// eslint-disable-next-line @typescript-eslint/no-unsafe-call -- TODO(RC3): Address type safety
      errorFn(new Error('test error'));
      // We could spy on Logger, but at least we cover the lines
    });

    it('should trigger reconnecting listener', () => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      const reconnectFn = client.on.mock.calls.find(
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
        (call: any) => call[0] === 'reconnecting',
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      )[1];
// eslint-disable-next-line @typescript-eslint/no-unsafe-call -- TODO(RC3): Address type safety
      reconnectFn();
      // Cover lines
    });

    it('should execute retryStrategy correctly', () => {
      // The Redis constructor mock is standard, so we can access its calls
      // ioredis is imported dynamically or we can just access it from jest.requireMock
// eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-require-imports, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      const RedisMock = require('ioredis').default;
// eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      const options = RedisMock.mock.calls[0][0];
// eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      const retryStrategy = options.retryStrategy;

// eslint-disable-next-line @typescript-eslint/no-unsafe-call -- TODO(RC3): Address type safety
      expect(retryStrategy(11)).toBeNull();
// eslint-disable-next-line @typescript-eslint/no-unsafe-call -- TODO(RC3): Address type safety
      expect(retryStrategy(2)).toBe(200);
// eslint-disable-next-line @typescript-eslint/no-unsafe-call -- TODO(RC3): Address type safety
      expect(retryStrategy(50)).toBeNull();
    });
  });

  it('should be defined', () => {
    expect(service).toBeDefined();
  });

  describe('onModuleInit', () => {
    it('should ping redis and log connection', async () => {
      await service.onModuleInit();
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      expect(client.ping).toHaveBeenCalled();
    });

    it('should throw error if ping fails', async () => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      client.ping.mockRejectedValue(new Error('Connection failed'));
      await expect(service.onModuleInit()).rejects.toThrow('Connection failed');
    });
  });

  describe('onModuleDestroy', () => {
    it('should quit redis client', async () => {
      await service.onModuleDestroy();
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      expect(client.quit).toHaveBeenCalled();
    });
  });

  describe('Core Operations', () => {
    it('get should return value', async () => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      client.get.mockResolvedValue('value');
      const result = await service.get('key');
      expect(result).toBe('value');
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      expect(client.get).toHaveBeenCalledWith('key');
    });

    it('set should set value with ttl', async () => {
      await service.set('key', 'value', 3600);
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      expect(client.set).toHaveBeenCalledWith('key', 'value', 'EX', 3600);
    });

    it('set should set value without ttl', async () => {
      await service.set('key', 'value');
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      expect(client.set).toHaveBeenCalledWith('key', 'value');
    });

    it('setNx should return true if OK', async () => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      client.set.mockResolvedValue('OK');
      const result = await service.setNx('key', 'value', 3600);
      expect(result).toBe(true);
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      expect(client.set).toHaveBeenCalledWith('key', 'value', 'EX', 3600, 'NX');
    });

    it('del should return deleted count', async () => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      client.del.mockResolvedValue(1);
      const result = await service.del('key');
      expect(result).toBe(1);
    });

    it('exists should return boolean', async () => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      client.exists.mockResolvedValue(1);
      const result = await service.exists('key');
      expect(result).toBe(true);
    });

    it('expire should return boolean', async () => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      client.expire.mockResolvedValue(1);
      const result = await service.expire('key', 3600);
      expect(result).toBe(true);
    });

    it('ttl should return remaining time', async () => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      client.ttl.mockResolvedValue(3600);
      const result = await service.ttl('key');
      expect(result).toBe(3600);
    });

    it('incr should increment value', async () => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      client.incr.mockResolvedValue(2);
      const result = await service.incr('key');
      expect(result).toBe(2);
    });

    it('incrBy should increment value by specified amount', async () => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      client.incrby.mockResolvedValue(5);
      const result = await service.incrBy('key', 5);
      expect(result).toBe(5);
    });
  });

  describe('JSON Operations', () => {
    it('getJson should return parsed object', async () => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      client.get.mockResolvedValue('{"test":"value"}');
      const result = await service.getJson('key');
      expect(result).toEqual({ test: 'value' });
