import { Roles } from '../../shared/decorators/roles.decorator';
import { UserRole } from '@shiftly/shared-types';

@Controller('timesheets')
@UseGuards(JwtAuthGuard, RolesGuard)
export class TimesheetsController {
  constructor(private readonly timesheetsService: TimesheetsService) {}

  @Post(':shiftId/submit')
  @Roles('WORKER')
  async submitTimesheet(
    @Param('shiftId') shiftId: string,
    @Body() body: { hoursWorked: number; notes?: string },
    @Request() req: any,
  ) {
    // Assuming the user's worker profile ID is not direct, but we use the user's ID to find their worker profile.
    // However, in shifts, workerId refers to the worker profile ID.
    // In previous files (e.g. shifts.controller.ts), req.user.profileId might be used.
    // For simplicity, we assume `req.user.profileId` or we lookup the worker.
    return this.timesheetsService.submitTimesheet(
      shiftId,
// eslint-disable-next-line @typescript-eslint/no-unsafe-argument, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      req.user.profileId,
      body.hoursWorked,
      body.notes,
    );
  }

  @Get('employer')
  @Roles('EMPLOYER')
  async getEmployerTimesheets(@Request() req: any) {
// eslint-disable-next-line @typescript-eslint/no-unsafe-argument, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
    return this.timesheetsService.getTimesheetsForEmployer(req.user.profileId);
  }

  @Post(':id/approve')
  @Roles('EMPLOYER')
  async approveTimesheet(@Param('id') id: string, @Request() req: any) {
// eslint-disable-next-line @typescript-eslint/no-unsafe-argument, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
    return this.timesheetsService.approveTimesheet(id, req.user.profileId);
  }

  @Post(':id/reject')
  @Roles('EMPLOYER')
  async rejectTimesheet(
    @Param('id') id: string,
    @Body() body: { rejectionReason: string },
    @Request() req: any,
  ) {
    return this.timesheetsService.rejectTimesheet(
      id,
// eslint-disable-next-line @typescript-eslint/no-unsafe-argument, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
      req.user.profileId,
      body.rejectionReason,
    );
  }
}

import {
  Injectable,
  NotFoundException,
  BadRequestException,
  ForbiddenException,
  Logger,
} from '@nestjs/common';
import { PrismaService } from '../../infrastructure/database/prisma.service';
import { EscrowService } from '../payments/escrow/escrow.service';
import { TimesheetStatus } from '@shiftly/shared-types';

@Injectable()
export class TimesheetsService {
  private readonly logger = new Logger(TimesheetsService.name);

  constructor(
    private readonly prisma: PrismaService,
    private readonly escrowService: EscrowService,
  ) {}

  async submitTimesheet(
    shiftId: string,
    workerId: string,
    hoursWorked: number,
    notes?: string,
  ) {
    const shift = await this.prisma.shift.findUnique({
      where: { id: shiftId },
      include: { timesheet: true },
    });

    if (!shift) {
      throw new NotFoundException('Shift not found');
    }

    if (shift.workerId !== workerId) {
// eslint-disable-next-line prettier/prettier -- TODO(RC3): Address type safety
      throw new ForbiddenException('Not authorized to submit timesheet for this shift');
    }

    if (shift.timesheet) {
      return this.prisma.timesheet.update({
        where: { id: shift.timesheet.id },
        data: {
          hoursWorked,
          notes,
          status: 'SUBMITTED',
          submittedAt: new Date(),
        },
      });
    }

    return this.prisma.timesheet.create({
      data: {
        shiftId,
        hoursWorked,
        notes,
        status: 'SUBMITTED',
        submittedAt: new Date(),
      },
    });
  }

  async getTimesheetsForEmployer(employerId: string) {
    return this.prisma.timesheet.findMany({
      where: {
        shift: {
          job: {
            employerId,
          },
        },
      },
      include: {
        shift: {
          include: {
            worker: {
              include: {
                user: {
                  select: {
                    email: true,
                  },
                },
              },
            },
            job: true,
          },
        },
      },
      orderBy: {
        updatedAt: 'desc',
      },
    });
  }

  async approveTimesheet(timesheetId: string, employerId: string) {
    const timesheet = await this.prisma.timesheet.findUnique({
      where: { id: timesheetId },
      include: {
        shift: {
          include: { job: true },
        },
      },
    });

    if (!timesheet) throw new NotFoundException('Timesheet not found');
    if (timesheet.shift.job.employerId !== employerId) {
      throw new ForbiddenException('Not authorized to approve this timesheet');
    }

    const updatedTimesheet = await this.prisma.timesheet.update({
      where: { id: timesheetId },
      data: {
        status: 'APPROVED',
        approvedAt: new Date(),
      },
    });

    try {
      await this.escrowService.releaseFunds(updatedTimesheet.id);
    } catch (error) {
      this.logger.error(
        `Failed to release escrow funds for timesheet ${timesheetId}:`,
        error,
      );
    }

    return updatedTimesheet;
  }

  async rejectTimesheet(
    timesheetId: string,
    employerId: string,
    rejectionReason: string,
  ) {
    const timesheet = await this.prisma.timesheet.findUnique({
      where: { id: timesheetId },
      include: { shift: { include: { job: true } } },
    });

    if (!timesheet) throw new NotFoundException('Timesheet not found');
    if (timesheet.shift.job.employerId !== employerId) {
      throw new ForbiddenException('Not authorized to reject this timesheet');
    }

    return this.prisma.timesheet.update({
      where: { id: timesheetId },
      data: {
        status: 'REJECTED',
        rejectedAt: new Date(),
        rejectionReason,
      },
    });
  }
}

