import {
  Injectable,
  NestInterceptor,
  ExecutionContext,
  CallHandler,
  Logger,
  ConflictException,
} from '@nestjs/common';
import { Observable, of, throwError } from 'rxjs';
import { tap, catchError } from 'rxjs/operators';
import { Request, Response } from 'express';
import { RedisService } from '../../infrastructure/redis/redis.service';

@Injectable()
export class IdempotencyInterceptor implements NestInterceptor {
  private readonly logger = new Logger(IdempotencyInterceptor.name);
  private readonly TTL_SECONDS = 86400; // 24 hours

  constructor(private readonly redis: RedisService) {}

  async intercept(
    context: ExecutionContext,
    next: CallHandler,
  ): Promise<Observable<unknown>> {
    const ctx = context.switchToHttp();
    const request = ctx.getRequest<Request>();
    const response = ctx.getResponse<Response>();

    const method = request.method;
    // Only apply idempotency to mutations
    if (method !== 'POST' && method !== 'PUT' && method !== 'PATCH') {
      return next.handle();
    }

    const idempotencyKey = request.headers['idempotency-key'] as string;
    if (!idempotencyKey) {
      return next.handle();
    }

// eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
    const userId = (request as any).user?.sub;
    if (!userId) {
      // If unauthenticated but has idempotency key, we could bypass or hash IP. Bypass for now.
      return next.handle();
    }

    const cacheKey = `idempotency:${userId}:${idempotencyKey}`;
    const cachedRecord = await this.redis.get(cacheKey);

    if (cachedRecord) {
      this.logger.debug(`Idempotency cache hit for key: ${cacheKey}`);
      try {
// eslint-disable-next-line @typescript-eslint/no-unsafe-assignment -- TODO(RC3): Address type safety
        const parsed = JSON.parse(cachedRecord);
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
        if (parsed.status === 'IN_PROGRESS') {
          throw new ConflictException(
            'Request with this Idempotency-Key is currently being processed.',
          );
        }
// eslint-disable-next-line prettier/prettier -- TODO(RC3): Address type safety

        // Restore response status and headers
// eslint-disable-next-line @typescript-eslint/no-unsafe-argument, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
        response.status(parsed.statusCode);
        response.setHeader('X-Idempotency-Cache-Hit', 'true');
// eslint-disable-next-line prettier/prettier -- TODO(RC3): Address type safety

// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
        return of(parsed.body);
      } catch (e) {
        if (e instanceof ConflictException) throw e;
// eslint-disable-next-line @typescript-eslint/restrict-template-expressions -- TODO(RC3): Address type safety
        this.logger.warn(`Failed to parse idempotency cache record: ${e}`);
      }
    }

    // Mark as in-progress to prevent concurrent execution
// eslint-disable-next-line prettier/prettier -- TODO(RC3): Address type safety
    await this.redis.set(cacheKey, JSON.stringify({ status: 'IN_PROGRESS' }), this.TTL_SECONDS);

    return next.handle().pipe(
// eslint-disable-next-line @typescript-eslint/no-misused-promises -- TODO(RC3): Address type safety
      tap(async (data) => {
        const responseData = {
          status: 'COMPLETED',
          statusCode: response.statusCode,
// eslint-disable-next-line @typescript-eslint/no-unsafe-assignment -- TODO(RC3): Address type safety
          body: data,
        };
// eslint-disable-next-line prettier/prettier -- TODO(RC3): Address type safety
        await this.redis.set(cacheKey, JSON.stringify(responseData), this.TTL_SECONDS);
      }),
      catchError((error: unknown) => {
        // If the request fails, clear the in-progress flag so they can retry safely
// eslint-disable-next-line prettier/prettier -- TODO(RC3): Address type safety
        this.redis.del(cacheKey).catch(e => this.logger.error('Failed to clear idempotency key on error', e));
        return throwError(() => error);
      }),
    );
  }
}

import { LoggingInterceptor } from './logging.interceptor';
import { ExecutionContext, Logger } from '@nestjs/common';
import { of, throwError } from 'rxjs';

jest.mock('uuid', () => ({
  v4: jest.fn(() => 'test-uuid'),
}));

describe('LoggingInterceptor', () => {
  let interceptor: LoggingInterceptor;
  let mockLogger: jest.Mocked<Logger>;
  let mockExecutionContext: ExecutionContext;
  let mockCallHandler: any;

  beforeEach(() => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-assignment -- TODO(RC3): Address type safety
    mockLogger = {
      debug: jest.fn(),
      log: jest.fn(),
      error: jest.fn(),
    } as any;

    interceptor = new LoggingInterceptor(mockLogger);

    mockExecutionContext = {
      switchToHttp: jest.fn().mockReturnValue({
        getRequest: jest.fn().mockReturnValue({
          method: 'GET',
          url: '/test',
          ip: '127.0.0.1',
          headers: {},
          user: { sub: 'user-123' },
        }),
        getResponse: jest.fn().mockReturnValue({
          statusCode: 200,
          setHeader: jest.fn(),
        }),
      }),
    } as unknown as ExecutionContext;

    mockCallHandler = {
      handle: jest.fn().mockReturnValue(of('test-response')),
    };

    // Mock Date.now for predictable duration
    jest.spyOn(Date, 'now').mockReturnValue(1000);
  });

  afterEach(() => {
    jest.restoreAllMocks();
  });

  it('should log incoming request and successful response', (done) => {
    let nowCount = 0;
    jest.spyOn(Date, 'now').mockImplementation(() => {
      nowCount++;
      return nowCount === 1 ? 1000 : 1050; // 50ms duration
    });

// eslint-disable-next-line @typescript-eslint/no-unsafe-argument -- TODO(RC3): Address type safety
    interceptor.intercept(mockExecutionContext, mockCallHandler).subscribe({
      next: (val) => {
        expect(val).toBe('test-response');
// eslint-disable-next-line @typescript-eslint/unbound-method -- TODO(RC3): Address type safety
        expect(mockLogger.debug).toHaveBeenCalledWith(
          '→ GET /test',
          expect.stringContaining(
            '"userId":"user-123","requestId":"test-uuid"',
          ),
        );
// eslint-disable-next-line @typescript-eslint/unbound-method -- TODO(RC3): Address type safety
        expect(mockLogger.log).toHaveBeenCalledWith(
          '← GET /test [50ms]',
          expect.stringContaining('"duration":50'),
        );
        done();
      },
    });
  });

  it('should log incoming request and error response', (done) => {
    const error = new Error('test-error');
// eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
    mockCallHandler.handle.mockReturnValue(throwError(() => error));

    let nowCount = 0;
    jest.spyOn(Date, 'now').mockImplementation(() => {
      nowCount++;
      return nowCount === 1 ? 1000 : 1020; // 20ms duration
    });

// eslint-disable-next-line @typescript-eslint/no-unsafe-argument -- TODO(RC3): Address type safety
    interceptor.intercept(mockExecutionContext, mockCallHandler).subscribe({
      error: (err) => {
        expect(err).toBe(error);
// eslint-disable-next-line @typescript-eslint/unbound-method -- TODO(RC3): Address type safety
        expect(mockLogger.debug).toHaveBeenCalled();
// eslint-disable-next-line @typescript-eslint/unbound-method -- TODO(RC3): Address type safety
        expect(mockLogger.error).toHaveBeenCalledWith(
          '← GET /test [20ms] ERROR',
          expect.stringContaining('"duration":20'),
        );
        done();
      },
    });
  });
});

import {
  Injectable,
  NestInterceptor,
  ExecutionContext,
  CallHandler,
  Logger,
} from '@nestjs/common';
import { Observable } from 'rxjs';
import { tap, catchError } from 'rxjs/operators';
import { Request, Response } from 'express';
import { throwError } from 'rxjs';
import { v4 as uuidv4 } from 'uuid';

@Injectable()
export class LoggingInterceptor implements NestInterceptor {
  constructor(private readonly logger: Logger) {}

  intercept(context: ExecutionContext, next: CallHandler): Observable<unknown> {
    const ctx = context.switchToHttp();
    const request = ctx.getRequest<Request>();
    const response = ctx.getResponse<Response>();
    const { method, url, ip } = request;
    const userId = (request as Request & { user?: { sub: string } }).user?.sub;
// eslint-disable-next-line prettier/prettier -- TODO(RC3): Address type safety

// eslint-disable-next-line prettier/prettier -- TODO(RC3): Address type safety
    const correlationId = (request.headers['x-correlation-id'] as string) ?? uuidv4();
    const requestId = (request.headers['x-request-id'] as string) ?? uuidv4();
// eslint-disable-next-line prettier/prettier -- TODO(RC3): Address type safety

    // Set headers on response
    response.setHeader('X-Request-Id', requestId);
    response.setHeader('X-Correlation-Id', correlationId);

    const startTime = Date.now();

    const logContext = { method, url, ip, userId, requestId, correlationId };

    this.logger.debug(`→ ${method} ${url}`, JSON.stringify(logContext));

    return next.handle().pipe(
      tap(() => {
        const duration = Date.now() - startTime;
        this.logger.log(
          `← ${method} ${url} [${duration}ms]`,
          JSON.stringify({ ...logContext, duration }),
        );
      }),
      catchError((error: unknown) => {
        const duration = Date.now() - startTime;
        this.logger.error(
          `← ${method} ${url} [${duration}ms] ERROR`,
          JSON.stringify({ ...logContext, duration }),
        );
        return throwError(() => error);
      }),
    );
  }
}

import {
  Injectable,
  NestInterceptor,
  ExecutionContext,
  CallHandler,
  Logger,
  RequestTimeoutException,
} from '@nestjs/common';
import { Observable, throwError, TimeoutError } from 'rxjs';
import { catchError, retry, timeout } from 'rxjs/operators';

@Injectable()
export class RetryInterceptor implements NestInterceptor {
  private readonly logger = new Logger(RetryInterceptor.name);

  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
// eslint-disable-next-line @typescript-eslint/no-unsafe-assignment -- TODO(RC3): Address type safety
    const req = context.switchToHttp().getRequest();
// eslint-disable-next-line prettier/prettier -- TODO(RC3): Address type safety

    // Only retry idempotent methods
    const idempotentMethods = ['GET', 'HEAD', 'OPTIONS', 'PUT', 'DELETE'];
// eslint-disable-next-line @typescript-eslint/no-unsafe-argument, @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
    const isIdempotent = idempotentMethods.includes(req.method.toUpperCase());

    return next.handle().pipe(
      // Timeout after 10 seconds
      timeout(10000),
      // Retry up to 3 times for idempotent requests if there's a TimeoutError or 5xx error
      retry({
        count: isIdempotent ? 2 : 0,
        delay: (error, retryCount) => {
// eslint-disable-next-line prettier/prettier, @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
          if (error instanceof TimeoutError || (error.status && error.status >= 500)) {
// eslint-disable-next-line prettier/prettier -- TODO(RC3): Address type safety
            this.logger.warn(`Request failed (Attempt ${retryCount}), retrying...`);
            return new Observable((subscriber) => {
              setTimeout(() => {
                subscriber.next(true);
                subscriber.complete();
              }, 1000 * retryCount); // Exponential-ish backoff
            });
          }
// eslint-disable-next-line @typescript-eslint/no-unsafe-return -- TODO(RC3): Address type safety
          return throwError(() => error);
        },
      }),
      catchError((err) => {
        if (err instanceof TimeoutError) {
          return throwError(() => new RequestTimeoutException());
        }
// eslint-disable-next-line @typescript-eslint/no-unsafe-return -- TODO(RC3): Address type safety
        return throwError(() => err);
      }),
    );
  }
}

import { TransformInterceptor } from './transform.interceptor';
import { ExecutionContext } from '@nestjs/common';
import { of } from 'rxjs';

jest.mock('uuid', () => ({
  v4: jest.fn(() => 'test-uuid'),
}));

describe('TransformInterceptor', () => {
  let interceptor: TransformInterceptor<any>;
  let mockExecutionContext: ExecutionContext;
  let mockCallHandler: any;
  let mockResponse: any;

  beforeEach(() => {
    interceptor = new TransformInterceptor();

    mockResponse = {
      setHeader: jest.fn(),
    };

    mockExecutionContext = {
      switchToHttp: jest.fn().mockReturnValue({
        getRequest: jest.fn().mockReturnValue({
          headers: {},
        }),
        getResponse: jest.fn().mockReturnValue(mockResponse),
      }),
    } as unknown as ExecutionContext;

    mockCallHandler = {
      handle: jest.fn().mockReturnValue(of({ data: 'test' })),
    };

    jest
      .spyOn(global.Date.prototype, 'toISOString')
      .mockReturnValue('2026-07-20T00:00:00.000Z');
  });

  afterEach(() => {
    jest.restoreAllMocks();
  });

  it('should transform response to SuccessResponse format', (done) => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-argument -- TODO(RC3): Address type safety
    interceptor.intercept(mockExecutionContext, mockCallHandler).subscribe({
      next: (val) => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
        expect(mockResponse.setHeader).toHaveBeenCalledWith(
          'X-Request-ID',
          'test-uuid',
        );
        expect(val).toEqual({
          success: true,
          data: { data: 'test' },
          meta: {
            timestamp: '2026-07-20T00:00:00.000Z',
            requestId: 'test-uuid',
          },
        });
        done();
      },
    });
  });

  it('should use existing x-request-id header if present', (done) => {
    mockExecutionContext.switchToHttp().getRequest = jest.fn().mockReturnValue({
      headers: { 'x-request-id': 'existing-uuid' },
    });

// eslint-disable-next-line @typescript-eslint/no-unsafe-argument -- TODO(RC3): Address type safety
    interceptor.intercept(mockExecutionContext, mockCallHandler).subscribe({
      next: (val) => {
// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
        expect(mockResponse.setHeader).toHaveBeenCalledWith(
          'X-Request-ID',
          'existing-uuid',
        );
        expect(val.meta.requestId).toBe('existing-uuid');
        done();
      },
    });
  });
});

import { createZodDto } from './zod-dto.util';
import { z } from 'zod';

describe('createZodDto', () => {
  it('should create a class with static schema', () => {
    const schema = z.object({ name: z.string() });
    const DtoClass = createZodDto(schema);

// eslint-disable-next-line @typescript-eslint/no-unsafe-member-access -- TODO(RC3): Address type safety
    expect((DtoClass as any).schema).toBe(schema);
  });

  it('should parse valid data successfully', () => {
    const schema = z.object({ name: z.string() });
    const DtoClass = createZodDto(schema);

// eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call -- TODO(RC3): Address type safety
    const instance = new (DtoClass as any)({ name: 'Test' });
    expect(instance).toEqual({ name: 'Test' });
  });

  it('should throw error on invalid data', () => {
    const schema = z.object({ name: z.string() });
    const DtoClass = createZodDto(schema);

// eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-return -- TODO(RC3): Address type safety
    expect(() => new (DtoClass as any)({ name: 123 })).toThrow();
  });

  it('should create empty instance if no data provided', () => {
    const schema = z.object({ name: z.string() });
    const DtoClass = createZodDto(schema);

    const instance = new DtoClass();
    expect(instance).toEqual({});
  });
});

import { NodeSDK } from '@opentelemetry/sdk-node';
import { getNodeAutoInstrumentations } from '@opentelemetry/auto-instrumentations-node';
import { OTLPTraceExporter } from '@opentelemetry/exporter-trace-otlp-http';
import { resourceFromAttributes } from '@opentelemetry/resources';
import { SEMRESATTRS_SERVICE_NAME } from '@opentelemetry/semantic-conventions';

const otlpEndpoint = process.env.OTLP_ENDPOINT;
const serviceName = process.env.OTLP_SERVICE_NAME || 'shiftly-api';

let sdk: NodeSDK | null = null;

if (otlpEndpoint) {
  sdk = new NodeSDK({
    resource: resourceFromAttributes({
      [SEMRESATTRS_SERVICE_NAME]: serviceName,
    }),
    traceExporter: new OTLPTraceExporter({
      url: `${otlpEndpoint}/v1/traces`,
    }),
    instrumentations: [
      getNodeAutoInstrumentations({
        '@opentelemetry/instrumentation-fs': { enabled: false },
        '@opentelemetry/instrumentation-pino': { enabled: false },
      }),
    ],
  });

  sdk.start();

  process.on('SIGTERM', () => {
// eslint-disable-next-line prettier/prettier -- TODO(RC3): Address type safety
    sdk?.shutdown()
      .then(() => console.log('Tracing terminated'))
      .catch((error) => console.log('Error terminating tracing', error))
      .finally(() => process.exit(0));
  });
}
